class Solution {
public:
    int maxLengthBetweenEqualCharacters(string s) {
        int max_len = -1;
        unordered_map<char, int> last_seen;
        for (int i = 0; i < s.length(); i++) {
            if (last_seen.find(s[i]) != last_seen.end()) {
                max_len = max(max_len, i - last_seen[s[i]] - 1);
            }
            last_seen[s[i]] = i;
        }
        return max_len;
    }
};
```

